function MediaGallery() {
  const { div } = tags;
  const images = [
    { thumb: '/images/photo-1.jpg', full: '/images/photo-1-full.jpg', alt: 'Mountain landscape' },
    { thumb: '/images/photo-2.jpg', full: '/images/photo-2-full.jpg', alt: 'Ocean sunset' },
    { thumb: '/images/photo-3.jpg', full: '/images/photo-3-full.jpg', alt: 'Forest trail' },
    { thumb: '/images/photo-4.jpg', full: '/images/photo-4-full.jpg', alt: 'City skyline' },
    { thumb: '/images/photo-5.jpg', full: '/images/photo-5-full.jpg', alt: 'Desert dunes' },
    { thumb: '/images/photo-6.jpg', full: '/images/photo-6-full.jpg', alt: 'Snowy peaks' }
  ];
  const [selected, setSelected] = createSignal(null);

  return div({},
    div({ class: css('_grid _gcaf250 _gap3 _p4') },
      ...images.map((img, i) =>
        div({ class: css('_overflow[hidden] _r4 _pointer _trans'), onclick: () => setSelected(i) },
          Image({ src: img.thumb, alt: img.alt, class: css('_wfull _h[200px] _object[cover]') })
        )
      )
    ),
    Modal({ visible: () => selected() !== null, onClose: () => setSelected(null) },
      selected() !== null ? Image({ src: images[selected()].full, alt: images[selected()].alt, class: css('_mw[90vw] _mh[80vh] _object[contain]') }) : null
    )
  );
}
